$docsLogsDir = Join-Path $repoRoot "docs\system_generated_logs"

# Ensure destination directory exists
if (-not (Test-Path $docsLogsDir)) {
    New-Item -ItemType Directory -Path $docsLogsDir | Out-Null
    Write-Host "Created directory: $docsLogsDir" -ForegroundColor Green
}

# Locate local .gemini brain directory
$userProfile = [System.Environment]::GetFolderPath('UserProfile')
$brainDir = Join-Path $userProfile ".gemini\antigravity\brain"

if (-not (Test-Path $brainDir)) {
    Write-Host "Antigravity brain directory not found at $brainDir" -ForegroundColor Yellow
    exit 0
}

Write-Host "Syncing conversations from $brainDir to $docsLogsDir..." -ForegroundColor Cyan

# Find all conversation directories
$conversations = Get-ChildItem -Path $brainDir -Directory

