    $convId = $conv.Name
    $destConvDir = Join-Path $docsLogsDir $convId

    $filesToSync = @()

    # Check for artifacts at the root of the conversation
    $artifactFiles = @("implementation_plan.md", "task.md", "walkthrough.md")
    foreach ($file in $artifactFiles) {
        $filePath = Join-Path $conv.FullName $file
        if (Test-Path $filePath) {
            $filesToSync += [PSCustomObject]@{
