"  Future<ExtractedCapture> extract(String rawText, {String? sender}) async {
    Response res;
    try {
      res = await _dio.post(
        _endpoint,
        options: Options(headers: {
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json',
        }),
        data: {
          'model': LakouConfig.claudeModel,
          'max_tokens': 1024,
          'system': _systemPrompt,
          'messages': [
            {
              'role': 'user',
              'content': 'Sender: ${sender ?? "unknown"}\n\nMessage:\n$rawText',
            }
          ],
        },
      );
    } on DioException catch (e) {
      final responseData = e.response?.data;
      throw Exception('Claude API call failed (HTTP ${e.response?.statusCode}): ${e.message}\nResponse: $responseData');
    }

    final data = res.data;
    if (data == null || data['content'] == null) {
      throw Exception('Claude returned no content (HTTP ${res.statusCode})');
    }
    final content = (data['content'] as List).first['text'] as String;
    final jsonStart = content.indexOf('{');
    final jsonEnd = content.lastIndexOf('}');
    if (jsonStart == -1 || jsonEnd == -1 || jsonEnd <= jsonStart) {
      throw Exception('Claude response contained no JSON: ${content.substring(0, content.length.clamp(0, 120))}');
    }
    final parsed = jsonDecode(content.substring(jsonStart, jsonEnd + 1)) as Map<String, dynamic>;
    return ExtractedCapture.fromJson(parsed);
  }"

