/// Structured result from Claude after parsing an SMS / shared text.
class ExtractedCapture {
  ExtractedCapture({
    required this.jobNoGuess,
    required this.summary,
    required this.actionItems,
    required this.dates,
    required this.markdown,
  });
  final String? jobNoGuess;
  final String summary;
  final List<String> actionItems;
  final List<String> dates;
  final String markdown;

  factory ExtractedCapture.fromJson(Map<String, dynamic> j) => ExtractedCapture(
        jobNoGuess: j['job_no'] as String?,
        summary: (j['summary'] as String?) ?? '',
        actionItems: ((j['action_items'] as List?) ?? const []).cast<String>(),
        dates: ((j['dates'] as List?) ?? const []).cast<String>(),
        markdown: (j['markdown'] as String?) ?? '',
      );
}

