"package com.greenstories.lakou

import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.util.Log

class BootReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        if (intent.action == Intent.ACTION_BOOT_COMPLETED) {
            Log.d("LakouBootReceiver", "Boot completed broadcast received.")

            // Check for running timer
            val prefs = context.getSharedPreferences("LakouTimerPrefs", Context.MODE_PRIVATE)
            val isActive = prefs.getBoolean("isActive", false)
            if (isActive) {
                Log.d("LakouBootReceiver", "Active timer found at boot, marking as interrupted.")
                prefs.edit().apply {
                    putBoolean("isActive", false)
                    putBoolean("interrupted", true)
                    putLong("interruptedEndTime", System.currentTimeMillis())
                    apply()
                }
            }

            // Re-schedule alarms
            AlarmReceiver.scheduleDefaultAlarms(context)
        }
    }
}
"

