"class TimerService extends StateNotifier<TimerState> {
  final Ref _ref;
  TimerService(this._ref) : super(TimerState());

  static const _channel = MethodChannel('lakou/timer');

  Future<void> startTimer({
    required int projectId,
    required String projectName,
    String category = 'design',
  }) async {
    try {
      await _channel.invokeMethod('startTimer', {'projectName': projectName});
      state = TimerState(
        isActive: true,
        projectName: projectName,
        projectId: projectId,
        startTime: DateTime.now(),
        category: category,
      );
    } on PlatformException catch (e) {
      debugPrint("Failed to start timer: '${e.message}'.");
    }
  }

  Future<void> stopTimer() async {
    try {
      final endTime = DateTime.now();
      final startTime = state.startTime;
      final projectId = state.projectId;
      final category = state.category;

      await _channel.invokeMethod('stopTimer');

      if (startTime != null && projectId != null) {
        final seconds = endTime.difference(startTime).inSeconds;
        if (seconds > 0) {
          final db = await _ref.read(dbProvider.future);
          await db.raw.insert('time_entries', {
            'project_id': projectId,
            'category': category,
            'started_at': startTime.millisecondsSinceEpoch,
            'ended_at': endTime.millisecondsSinceEpoch,
            'seconds': seconds,
            'note': '',
          });
        }
      }

      state = TimerState(isActive: false);
    } on PlatformException catch (e) {
      debugPrint("Failed to stop timer: '${e.message}'.");
    }
  }
}"

