"  static Future<LakouDb> open() async {
    final dir = await getApplicationDocumentsDirectory();
    final path = p.join(dir.path, 'tpm.db');
    final db = await openDatabase(
      path,
      version: 3,
      onCreate: (db, version) async {
        await _migrateV1(db);
        await _migrateV2(db);
        await _migrateV3(db);
      },
      onUpgrade: (db, oldV, newV) async {
        if (oldV < 2) await _migrateV2(db);
        if (oldV < 3) await _migrateV3(db);
      },
    );
    return LakouDb._(db);
  }

  /// v3: tasks get a planned_date column for the Morning Planner feature.
  static Future<void> _migrateV3(Database db) async {
    await db.execute(
      "ALTER TABLE tasks ADD COLUMN planned_date TEXT",
    );
  }

  /// v2: captures get a status column ('pending' | 'assigned' | 'archived').
  /// Archived captures are kept as local-only pointers so Tom can resurrect
  /// them later from the original SMS/MMS thread.
  static Future<void> _migrateV2(Database db) async {
    await db.execute(
      "ALTER TABLE captures ADD COLUMN status TEXT NOT NULL DEFAULT 'pending'",
    );
    // Anything already on disk with a dropbox_path was saved to a project.
    await db.execute(
      "UPDATE captures SET status = 'assigned' WHERE dropbox_path IS NOT NULL",
    );
  }"

