class DockObserver extends StatefulWidget {
  const DockObserver({super.key, required this.child, required this.navigatorKey});
  final Widget child;
  final GlobalKey<NavigatorState> navigatorKey;

  @override
  State<DockObserver> createState() => _DockObserverState();
}

class _DockObserverState extends State<DockObserver> {
  final _battery = Battery();
  StreamSubscription? _batterySub;
  StreamSubscription? _sensorSub;

  bool _isCharging = false;
  bool _isLandscape = false;
  bool _isDocked = false;

  @override
  void initState() {
    super.initState();
    _initObservers();
  }

  @override
  void dispose() {
    _batterySub?.cancel();
    _sensorSub?.cancel();
    super.dispose();
  }

  Future<void> _initObservers() async {
    // Check initial battery state
    try {
      final state = await _battery.batteryState;
      _updateCharging(state);
    } catch (_) {}

    _batterySub = _battery.onBatteryStateChanged.listen((state) {
      _updateCharging(state);
    });

    _sensorSub = accelerometerEventStream().listen((event) {
      // Tom's Pixel 10 Pro XL: standard accelerometer values are in m/s^2.
      // If the phone is landscape, gravity is mostly along the X-axis (abs > 6.5)
      // and Y-axis gravity is low (abs < 5.0).
      final isLandscapeNow = event.x.abs() > 6.5 && event.y.abs() < 5.0;
      if (isLandscapeNow != _isLandscape) {
        _isLandscape = isLandscapeNow;
        _evaluateDockState();
      }
    });
