"class Project {
  final int id;
  final String jobNo;
  final String name;
  final String dropboxPath;
  final String status;
  final int secondsTracked;

  Project({
    required this.id,
    required this.jobNo,
    required this.name,
    required this.dropboxPath,
    required this.status,
    this.secondsTracked = 0,
  });

  factory Project.fromMap(Map<String, dynamic> map) {
    return Project(
      id: map['id'] as int,
      jobNo: map['job_no'] as String,
      name: map['name'] as String,
      dropboxPath: map['dropbox_path'] as String,
      status: (map['status'] as String?) ?? 'active',
      secondsTracked: (map['seconds_tracked'] as num?)?.toInt() ?? 0,
    );
  }
}


final projectsProvider = FutureProvider<List<Project>>((ref) async {
  final db = await ref.watch(dbProvider.future);
  final maps = await db.raw.rawQuery('''
    SELECT p.*, COALESCE(SUM(t.seconds), 0) AS seconds_tracked
    FROM projects p
    LEFT JOIN time_entries t ON p.id = t.project_id
    WHERE p.status != 'archived'
    GROUP BY p.id
    ORDER BY p.job_no DESC
  ''');
  return maps.map((m) => Project.fromMap(m)).toList();
});"

