"  static Future<LakouDb> open() async {
    final dir = await getApplicationDocumentsDirectory();
    final path = p.join(dir.path, 'tpm.db');
    final db = await openDatabase(
      path,
      version: 4,
      onCreate: (db, version) async {
        await _migrateV1(db);
        await _migrateV2(db);
        await _migrateV3(db);
        await _migrateV4(db);
      },
      onUpgrade: (db, oldV, newV) async {
        if (oldV < 2) await _migrateV2(db);
        if (oldV < 3) await _migrateV3(db);
        if (oldV < 4) await _migrateV4(db);
      },
    );
    return LakouDb._(db);
  }

  /// v4: Fieldy meeting capture integration
  static Future<void> _migrateV4(Database db) async {
    final batch = db.batch();

    batch.execute('''
      CREATE TABLE dismissed_fieldy_conversations (
        fieldy_id    TEXT PRIMARY KEY,
        dismissed_at INTEGER NOT NULL
      )
    ''');

    batch.execute('''
      CREATE TABLE meetings (
        id               INTEGER PRIMARY KEY AUTOINCREMENT,
        project_id       INTEGER NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
        fieldy_id        TEXT UNIQUE,
        title            TEXT NOT NULL,
        summary          TEXT,
        filepath         TEXT NOT NULL,
        meeting_date     INTEGER NOT NULL,
        duration_seconds INTEGER,
        created_at       INTEGER NOT NULL
      )
    ''');

    batch.execute('''
      CREATE TABLE meeting_attendees (
        meeting_id    INTEGER NOT NULL REFERENCES meetings(id) ON DELETE CASCADE,
        consultant_id INTEGER NOT NULL REFERENCES consultants(id) ON DELETE CASCADE,
        role          TEXT,
        PRIMARY KEY (meeting_id, consultant_id, role)
      )
    ''');

