"  Future<void> _fetchMore({bool clear = false}) async {
    final client = ref.read(fieldyClientProvider);
    var cursor = clear ? null : _nextCursor;
    var hasMore = true;
    final List<FieldyConversation> filtered = [];

    // Loop until we get some conversations to display or there are no more pages.
    // Limit to 5 pages per fetch request to avoid long API hangs or rate limits.
    int pagesFetched = 0;
    while (hasMore && filtered.length < 5 && pagesFetched < 5) {
      final result = await client.listConversations(
        pageSize: 20,
        cursor: cursor,
      );
      final List<FieldyConversation> fetched = (result['entries'] as List).cast<FieldyConversation>();
      cursor = result['nextCursor'] as String?;
      hasMore = result['hasMore'] as bool;
      pagesFetched++;

      // Filter out dismissed or already assigned ones
      final pageFiltered = fetched.where((c) => !_dismissedIds.contains(c.id) && !_assignedIds.contains(c.id)).toList();
      filtered.addAll(pageFiltered);

      if (cursor == null) break;
    }

    _nextCursor = cursor;
    _hasMore = hasMore;

    setState(() {
      if (clear) {
        _conversations.clear();
      }
      _conversations.addAll(filtered);
    });
  }"

