      Trace.log('sms', 'channel call ${call.method}');
      if (call.method == 'onSmsReceived') {
        final Map<dynamic, dynamic> args = call.arguments;
        final String sender = args['sender'] ?? 'Unknown';
        final String? displayName = args['displayName'] as String?;
        final String body = args['body'] ?? '';
        final int timestamp = args['timestamp'] ?? DateTime.now().millisecondsSinceEpoch;

        Trace.log('sms', 'onSmsReceived',
