    batch.execute("ALTER TABLE projects ADD COLUMN billing_method TEXT DEFAULT 'hourly'");
    batch.execute("ALTER TABLE projects ADD COLUMN billing_frequency TEXT DEFAULT 'monthly'");
    await batch.commit(noResult: true);
  }"

