class ConsultantRow {
  final int id;
  final String name;
  final String? firm;
  final String? role;
  final String? email;
  final String? phone;
  final String? contactId;
  final int timesUsed;
  final int? lastUsed;
  final bool pinned;

  ConsultantRow({
    required this.id,
    required this.name,
    this.firm,
    this.role,
    this.email,
    this.phone,
    this.contactId,
    required this.timesUsed,
    this.lastUsed,
    required this.pinned,
  });

  factory ConsultantRow.fromMap(Map<String, dynamic> map) {
    return ConsultantRow(
      id: map['id'] as int,
      name: map['name'] as String,
      firm: map['firm'] as String?,
      role: map['role'] as String?,
      email: map['email'] as String?,
      phone: map['phone'] as String?,
      contactId: map['contact_id'] as String?,
      timesUsed: map['times_used'] as int? ?? 0,
      lastUsed: map['last_used'] as int?,
      pinned: (map['pinned'] as int? ?? 0) == 1,
    );
  }
}

class ConsultantsRepo {
  final LakouDb db;
  ConsultantsRepo(this.db);

  Future<List<ConsultantRow>> list(String query) async {
    final clean = query.trim().toLowerCase();
    List<Map<String, dynamic>> rows;
    if (clean.isEmpty) {
      rows = await db.raw.query(
        'consultants',
        orderBy: 'pinned DESC, times_used DESC, name ASC',
      );
    } else {
      rows = await db.raw.query(
        'consultants',
        where: 'name LIKE ? OR firm LIKE ? OR role LIKE ?',
        whereArgs: ['%$clean%', '%$clean%', '%$clean%'],
        orderBy: 'pinned DESC, times_used DESC, name ASC',
      );
    }
    return rows.map((r) => ConsultantRow.fromMap(r)).toList();
  }

  Future<void> togglePinned(int id, bool pinned) async {
    await db.raw.update(
      'consultants',
      {'pinned': pinned ? 1 : 0},
      where: 'id = ?',
      whereArgs: [id],
